  templateMetadata?: AuthoredFamilyTemplateMetadata;
  categorySettings: AuthoredFamilyCategorySettings;
  viewRange: AuthoredFamilyViewRange;
  refPlanes: AuthoredFamilyRefPlane[];
  params: AuthoredFamilyParam[];
