/**
 * FAM-03 — bind a geometry node's visibility to a host boolean param.
 *
 * The node is rendered iff `Boolean(hostParams[paramName]) === whenTrue`.
 * Default semantics (when the field is absent): always visible.
 */
export interface VisibilityBinding {
  paramName: string;
  /** Show the node when the bound param's truthiness equals this. */
  whenTrue: boolean;
}

/**
 * VIE-02 — per-detail-level visibility for a single family geometry node.
 *
 * Defaults: every level visible (i.e. an unset key reads as `true`). Set
 * a key to `false` to hide the node when the resolver runs at the
 * matching plan detail level.
 */
export interface VisibilityByDetailLevel {
  coarse?: boolean;
  medium?: boolean;
  fine?: boolean;
}

export type FamilyVisibilityViewType =
  | 'plan_rcp'
  | 'front_back'
  | 'left_right'
  | 'three_d'
  | 'elevation'
  | 'section';

/**
 * F-059 — per-view-type visibility for a single family geometry node.
 *
 * Defaults: every view type visible. Set a key to `false` to hide the
 * node when the resolver/editor preview runs in the matching view type.
 */
export type VisibilityByViewType = Partial<Record<FamilyVisibilityViewType, boolean>>;

export interface FamilyPlanViewRange {
  topOffsetMm: number;
  cutPlaneOffsetMm: number;
  bottomOffsetMm: number;
  viewDepthOffsetMm: number;
}

export type ParametricLengthExpression =
  | number
  | { kind: 'param'; paramName: string; fallbackMm?: number }
  | { kind: 'formula'; expression: string; fallbackMm?: number };

export type SweepParametricProfile =
  | {
      kind: 'rectangle';
      minX: ParametricLengthExpression;
      maxX: ParametricLengthExpression;
      minY: ParametricLengthExpression;
      maxY: ParametricLengthExpression;
