  });
  return n;
}

function countFamilySemanticLines(root: THREE.Object3D, semanticKind: string): number {
  let n = 0;
  root.traverse((o) => {
    if (o instanceof THREE.Line && o.userData.familySymbolicSemanticKind === semanticKind) n += 1;
  });
  return n;
}

